{
  "sentences": [
    {
      "text": "可以給我一個袋子嗎？",
      "pinyin": "Kěyǐ gěi wǒ yī gè dàizi ma?",
      "pinyin_numeric": "ke3 yi3 gei3 wo3 yi1 ge4 dai4 zi0 ma0",
      "translation_en": "Can you give me a bag?",
      "translation_ko": "가방 하나 주실 수 있나요?"
    },
    {
      "text": "可以幫我拿一杯水嗎？",
      "pinyin": "Kěyǐ bāng wǒ ná yī bēi shuǐ ma?",
      "pinyin_numeric": "ke3 yi3 bang1 wo3 na2 yi1 bei1 shui3 ma0",
      "translation_en": "Can you help me get a glass of water?",
      "translation_ko": "물 한 잔 가져다 주실 수 있나요?"
    },
    {
      "text": "可以給我菜單嗎？",
      "pinyin": "Kěyǐ gěi wǒ càidān ma?",
      "pinyin_numeric": "ke3 yi3 gei3 wo3 cai4 dan1 ma0",
      "translation_en": "Can you give me the menu?",
      "translation_ko": "메뉴판 좀 주실 수 있나요?"
    },
    {
      "text": "可以幫我點一杯拿鐵嗎？",
      "pinyin": "Kěyǐ bāng wǒ diǎn yī bēi nǎtiě ma?",
      "pinyin_numeric": "ke3 yi3 bang1 wo3 dian3 yi1 bei1 na3 tie3 ma0",
      "translation_en": "Can you help me order a latte?",
      "translation_ko": "라떼 한 잔 주문해 주실 수 있나요?"
    },
    {
      "text": "可以給我發票嗎？",
      "pinyin": "Kěyǐ gěi wǒ fāpiào ma?",
      "pinyin_numeric": "ke3 yi3 gei3 wo3 fa1 piao4 ma0",
      "translation_en": "Can you give me the receipt?",
      "translation_ko": "영수증 주실 수 있나요?"
    },
    {
      "text": "可以幫我加珍珠嗎？",
      "pinyin": "Kěyǐ bāng wǒ jiā zhēnzhū ma?",
      "pinyin_numeric": "ke3 yi3 bang1 wo3 jia1 zhen1 zhu1 ma0",
      "translation_en": "Can you help me add boba pearls?",
      "translation_ko": "타피오카 펄 추가해 주실 수 있나요?"
    },
    {
      "text": "可以給我小杯的紅茶嗎？",
      "pinyin": "Kěyǐ gěi wǒ xiǎo bēi de hóngchá ma?",
      "pinyin_numeric": "ke3 yi3 gei3 wo3 xiao3 bei1 de0 hong2 cha2 ma0",
      "translation_en": "Can you give me a small black tea?",
      "translation_ko": "작은 컵 홍차 주실 수 있나요?"
    },
    {
      "text": "可以幫我拿吸管嗎？",
      "pinyin": "Kěyǐ bāng wǒ ná xīguǎn ma?",
      "pinyin_numeric": "ke3 yi3 bang1 wo3 na2 xi1 guan3 ma0",
      "translation_en": "Can you help me get a straw?",
      "translation_ko": "빨대 좀 가져다 주실 수 있나요?"
    },
    {
      "text": "可以給我半糖的豆漿嗎？",
      "pinyin": "Kěyǐ gěi wǒ bàn táng de dòujiāng ma?",
      "pinyin_numeric": "ke3 yi3 gei3 wo3 ban4 tang2 de0 dou4 jiang1 ma0",
      "translation_en": "Can you give me half-sugar soy milk?",
      "translation_ko": "반당 두유 주실 수 있나요?"
    },
    {
      "text": "可以幫我外帶嗎？",
      "pinyin": "Kěyǐ bāng wǒ wàidài ma?",
      "pinyin_numeric": "ke3 yi3 bang1 wo3 wai4 dai4 ma0",
      "translation_en": "Can you help me with takeout?",
      "translation_ko": "포장해 주실 수 있나요?"
    }
  ]
}
